### Suggested Improvements

Here's what an improved version would look like:

```js
const express = require('express');
const helmet = require('helmet');          // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();

// --- Security Middleware ---
app.use(helmet());                         // Sets secure HTTP headers
app.use(express.json({ limit: '10kb' })); // Body parser with size limit to prevent large payload attacks
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — prevent brute force / DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable X-Powered-By (helmet does this, but being explicit)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate query parameters if filtering is supported
    const allowedParams = ['page', 'limit'];
    const invalidParams = Object.keys(req.query).filter(
      (key) => !allowedParams.includes(key)
    );
    if (invalidParams.length > 0) {
      return res.status(400).json({
        error: 'Invalid query parameters',
        invalid: invalidParams,
      });
    }

    // In production, avoid exposing emails in list endpoints
    // or require authentication first
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];

    res.json(users);
  } catch (err) {
    next(err); // Forward to global error handler
  }
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to recognize it as an error handler
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);

  // Never leak stack traces or internal details to clients
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error'
        : err.message,
  });
});

// --- Server Start ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

