const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const morgan = require('morgan');         // Request logging

const app = express();

// --- Security Middleware ---
app.use(helmet());                        // Sets various HTTP security headers
app.use(express.json({ limit: '10kb' })); // Parse JSON with size limit (prevent large payloads)
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate Limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Request Logging ---
app.use(morgan('combined'));

// --- Disable fingerprinting ---
app.disable('x-powered-by'); // helmet does this too, but explicit is good

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In production, sanitize/validate any query params before use
